                if (index < count - 1) {
                    buffer[index++] = (char) (56320 + random.nextInt(128));
                    buffer[index++] = ch;
                }
            } else {
                // Normal character
                buffer[index++] = ch;
            }
        }
    }
    return new String(buffer);
}
