            end = 'z' + 1; // Set end to 'z' for letters
            start = ' ';   // Set start to space for printable characters
        }
    }

    char[] buffer = new char[count];
    int gap = end - start;

    // Ensure the gap is positive
    if (gap <= 0) {
        throw new IllegalArgumentException("Invalid character range: start should be less than end.");
    }

    int index = 0; // To track the position in the buffer

    while (index < count) {
        char ch;
        if (chars == null) {
            ch = (char) (random.nextInt(gap) + start);
        } else {
            ch = chars[random.nextInt(chars.length)];
        }

        // Check if the character is valid
        boolean isValid = (letters && Character.isLetter(ch)) || 
