                          (!letters && !numbers);

        if (isValid) {
            // Handle surrogate pairs
            if (Character.isHighSurrogate(ch) || Character.isLowSurrogate(ch)) {
                // Skip the character if it's a private high surrogate
                if (Character.isHighSurrogate(ch) && (ch >= 55296 && ch <= 56191)) {
                    continue; // Skip private high surrogate
